arguments.command:
$headers = @{ 'Authorization' = "Bearer $env:NOTION_TOKEN"; 'Notion-Version' = '2025-09-03'; 'Content-Type' = 'application/json' }
$pageId = '3290a0b1-97cc-801a-8240-e78d3bfe0e74'
$resp = Invoke-RestMethod -Method Get -Uri "https://api.notion.com/v1/blocks/$pageId/children?page_size=100" -Headers $headers
foreach($b in $resp.results){
  $txt = ''
  switch($b.type){
    'paragraph' { if($b.paragraph.rich_text.Count -gt 0){ $txt = $b.paragraph.rich_text[0].plain_text } }
    'heading_2' { if($b.heading_2.rich_text.Count -gt 0){ $txt = $b.heading_2.rich_text[0].plain_text } }
    'heading_3' { if($b.heading_3.rich_text.Count -gt 0){ $txt = $b.heading_3.rich_text[0].plain_text } }
    'bulleted_list_item' { if($b.bulleted_list_item.rich_text.Count -gt 0){ $txt = $b.bulleted_list_item.rich_text[0].plain_text } }
  }
  if($txt -match '\?' -or $txt -match 'Atlas test block'){
    $body = @{ archived = $true } | ConvertTo-Json
    Invoke-RestMethod -Method Patch -Uri "https://api.notion.com/v1/blocks/$($b.id)" -Headers $headers -Body $body | Out-Null
  }
}
'OK'

